ALTER TABLE "consultations" DROP CONSTRAINT "consultations_context_check";--> statement-breakpoint
CREATE UNIQUE INDEX "consultations_slot_unique_idx" ON "consultations" USING btree ("posyandu_id","consultation_type","scheduled_at") WHERE status != 'cancelled' AND deleted_at IS NULL;--> statement-breakpoint
CREATE UNIQUE INDEX "consultations_parent_schedule_unique_idx" ON "consultations" USING btree ("parent_id","scheduled_at") WHERE status != 'cancelled' AND deleted_at IS NULL;--> statement-breakpoint
ALTER TABLE "consultations" ADD CONSTRAINT "consultations_context_check" CHECK (("consultations"."consultation_type" = 'pregnancy' AND "consultations"."pregnancy_record_id" IS NOT NULL AND "consultations"."children_id" IS NULL) OR ("consultations"."consultation_type" = 'child_development' AND "consultations"."children_id" IS NOT NULL AND "consultations"."pregnancy_record_id" IS NULL) OR ("consultations"."consultation_type" = 'general' AND "consultations"."pregnancy_record_id" IS NULL AND "consultations"."children_id" IS NULL));